#include<iostream>
using namespace std;
int x, y, z, n, m, c;
int main() {
	cin >> x >> y >> z >> n >> m;
	for(int i = 0; i <= m; i++) {
		for(int j = 0; j <= m - i; j++) {
			int a=i * x + j * y + (m - i - j) / z;
			if(a==n&&(m-i-j)%z==0) {
				c+=1;
			}
		}
	}
	cout << c;
	return 0;
}
